#include <iostream>
#include <queue>

using namespace std;

class Node {
    int val, key;
    Node *left, *right;
    Node(int key, int val) : key(key), val(val), left(nullptr), right(nullptr) {}
};

class Solution {
public:
    Node* deleteNode(Node* root, int key) {
        if (root == nullptr) return nullptr;
        if (root->val == key) {
            Node* temp = root;
            if (root->left == nullptr && root->right == nullptr)
                return nullptr;
            if (root->left == nullptr) return root->right;
            if (root->right == nullptr) return root->left;
            Node* temp1 = root;
            Node* temp2 = root->left;
            while (temp2->right != nullptr) {
                temp1 = temp2;
                temp2 = temp2->right;
            }
            root->val = temp2->key;
            root->left = temp2->left;
            delete temp2;
            return root;
        }
        root->left = deleteNode(root->left, key);
        root->right = deleteNode(root->right, key);
        return root;
    }
};

int main() {
    Solution s;
    Node* root = nullptr;
    int key;
    while (true) {
        std::cin >> key;
        if (!std::cin) break;
        root = s.deleteNode(root, key);
    }
    return 0;
}
